async function retry(fn, { maxAttempts = 3, baseDelay = 1000, factor = 2 } = {}) {
  let lastError;
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn(attempt);
    } catch (err) {
      lastError = err;
      if (attempt < maxAttempts - 1) {
        await new Promise(r => setTimeout(r, baseDelay * Math.pow(factor, attempt)));
      }
    }
  }
  throw lastError;
}

