import time
import functools

def retry(max_attempts=3, base_delay=1.0, factor=2.0):
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            last_error = None
            for attempt in range(max_attempts):
                try:
                    return fn(*args, **kwargs)
                except Exception as e:
                    last_error = e
                    if attempt < max_attempts - 1:
                        time.sleep(base_delay * (factor ** attempt))
            raise last_error
        return wrapper
    return decorator

