func WorkerPool(numWorkers int, tasks []func()) {
	ch := make(chan func(), len(tasks))
	var wg sync.WaitGroup

	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for task := range ch {
				task()
			}
		}()
	}

	for _, task := range tasks {
		ch <- task
	}
	close(ch)
	wg.Wait()
}

