use std::thread;
use std::time::Duration;

pub fn retry<F, T, E>(max_attempts: usize, base_delay: Duration, mut f: F) -> Result<T, E>
where
    F: FnMut() -> Result<T, E>,
{
    let mut last_err = None;
    for attempt in 0..max_attempts {
        match f() {
            Ok(val) => return Ok(val),
            Err(e) => {
                last_err = Some(e);
                if attempt < max_attempts - 1 {
                    thread::sleep(base_delay * 2u32.pow(attempt as u32));
                }
            }
        }
    }
    Err(last_err.unwrap())
}

