type EventMap = Record<string, any[]>;

class TypedEmitter<T extends EventMap> {
  private handlers: { [K in keyof T]?: Array<(...args: T[K]) => void> } = {};

  on<K extends keyof T>(event: K, handler: (...args: T[K]) => void): void {
    (this.handlers[event] = this.handlers[event] || []).push(handler);
  }

  off<K extends keyof T>(event: K, handler: (...args: T[K]) => void): void {
    const list = this.handlers[event];
    if (list) this.handlers[event] = list.filter(h => h !== handler) as any;
  }

  emit<K extends keyof T>(event: K, ...args: T[K]): void {
    for (const handler of this.handlers[event] || []) handler(...args);
  }
}

